unit lipdecide;

interface

uses
  globals;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

uses
  Math;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  diff, maxab, tol, log10v: real;
  expv: integer;
begin
  if A = B then
  begin
    REALCOMPARE := EQ;
    exit;
  end;

  maxab := abs(A);
  if abs(B) > maxab then
    maxab := abs(B);

  if maxab = 0.0 then
  begin
    REALCOMPARE := EQ;
    exit;
  end;

  log10v := ln(maxab) / ln(10.0);
  expv := floor(log10v);
  tol := 0.5 * power(10.0, expv - 5);
  diff := A - B;

  if abs(diff) <= tol then
    REALCOMPARE := EQ
  else if diff < 0.0 then
    REALCOMPARE := LT
  else
    REALCOMPARE := GT;
end;

function GreaterThan(A, B: real): boolean;
begin
  GreaterThan := REALCOMPARE(A, B) = GT;
end;

function LessThan(A, B: real): boolean;
begin
  LessThan := REALCOMPARE(A, B) = LT;
end;

function EqualTo(A, B: real): boolean;
begin
  EqualTo := REALCOMPARE(A, B) = EQ;
end;

function Dist(x1, y1, x2, y2: real): real;
begin
  Dist := sqrt(sqr(x1 - x2) + sqr(y1 - y2));
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0);
end;

function CanContainInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  a, b, c, maxd, other1, other2, area, rmin: real;
begin
  a := Dist(x1, y1, x2, y2);
  b := Dist(x2, y2, x3, y3);
  c := Dist(x3, y3, x1, y1);

  maxd := a;
  if GreaterThan(b, maxd) then
    maxd := b;
  if GreaterThan(c, maxd) then
    maxd := c;

  area := TriangleArea(x1, y1, x2, y2, x3, y3);
  if EqualTo(area, 0.0) then
    rmin := maxd / 2.0
  else
  begin
    if EqualTo(maxd, a) then
    begin
      other1 := b;
      other2 := c;
    end
    else if EqualTo(maxd, b) then
    begin
      other1 := a;
      other2 := c;
    end
    else
    begin
      other1 := a;
      other2 := b;
    end;

    if REALCOMPARE(maxd * maxd, other1 * other1 + other2 * other2) <> LT then
      rmin := maxd / 2.0
    else
      rmin := (a * b * c) / (4.0 * area);
  end;

  CanContainInCircle := not GreaterThan(rmin, radius);
end;

function AngleAtVertex(x1, y1, x2, y2, x3, y3: real; var defined: boolean): real;
var
  v1x, v1y, v2x, v2y, len1, len2, dotp, cosang: real;
begin
  v1x := x1 - x2;
  v1y := y1 - y2;
  v2x := x3 - x2;
  v2y := y3 - y2;
  len1 := sqrt(sqr(v1x) + sqr(v1y));
  len2 := sqrt(sqr(v2x) + sqr(v2y));

  if EqualTo(len1, 0.0) or EqualTo(len2, 0.0) then
  begin
    defined := false;
    AngleAtVertex := 0.0;
    exit;
  end;

  defined := true;
  dotp := v1x * v2x + v1y * v2y;
  cosang := dotp / (len1 * len2);
  if GreaterThan(cosang, 1.0) then
    cosang := 1.0
  else if LessThan(cosang, -1.0) then
    cosang := -1.0;

  AngleAtVertex := arccos(cosang);
end;

function Quadrant(x, y: real): integer;
begin
  if (REALCOMPARE(x, 0.0) <> LT) and (REALCOMPARE(y, 0.0) <> LT) then
    Quadrant := 1
  else if (REALCOMPARE(x, 0.0) = LT) and (REALCOMPARE(y, 0.0) <> LT) then
    Quadrant := 2
  else if (REALCOMPARE(x, 0.0) = LT) and (REALCOMPARE(y, 0.0) = LT) then
    Quadrant := 3
  else
    Quadrant := 4;
end;

procedure DECIDE;
var
  i, j, k, startIdx, endIdx: integer;
  defined: boolean;
  angle, distp, denom, num, x1, y1, x2, y2: real;
  found1, found2, alltrue: boolean;
  qcount: integer;
  qseen: array[1..4] of boolean;
begin
  for i := 1 to 15 do
    CMV[i] := false;

  { LIC 1 }
  for i := 1 to NUMPOINTS - 1 do
    if GreaterThan(Dist(X[i], Y[i], X[i + 1], Y[i + 1]), PARAMETERS.LENGTH1) then
      CMV[1] := true;

  { LIC 2 }
  for i := 1 to NUMPOINTS - 2 do
    if not CanContainInCircle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], PARAMETERS.RADIUS1) then
      CMV[2] := true;

  { LIC 3 }
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := AngleAtVertex(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], defined);
    if defined then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        CMV[3] := true;
    end;
  end;

  { LIC 4 }
  for i := 1 to NUMPOINTS - 2 do
    if GreaterThan(TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]), PARAMETERS.AREA1) then
      CMV[4] := true;

  { LIC 5 }
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for j := 1 to 4 do
      qseen[j] := false;
    qcount := 0;
    for j := i to i + PARAMETERS.Q_PTS - 1 do
    begin
      k := Quadrant(X[j], Y[j]);
      if not qseen[k] then
      begin
        qseen[k] := true;
        qcount := qcount + 1;
      end;
    end;
    if qcount > PARAMETERS.QUADS then
      CMV[5] := true;
  end;

  { LIC 6 }
  for i := 1 to NUMPOINTS - 1 do
    if LessThan(X[i + 1] - X[i], 0.0) then
      CMV[6] := true;

  { LIC 7 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      startIdx := i;
      endIdx := i + PARAMETERS.N_PTS - 1;
      x1 := X[startIdx];
      y1 := Y[startIdx];
      x2 := X[endIdx];
      y2 := Y[endIdx];

      if EqualTo(x1, x2) and EqualTo(y1, y2) then
      begin
        for j := startIdx + 1 to endIdx - 1 do
        begin
          distp := Dist(x1, y1, X[j], Y[j]);
          if GreaterThan(distp, PARAMETERS.DIST) then
            CMV[7] := true;
        end;
      end
      else
      begin
        denom := sqrt(sqr(y2 - y1) + sqr(x2 - x1));
        for j := startIdx + 1 to endIdx - 1 do
        begin
          num := abs((y2 - y1) * X[j] - (x2 - x1) * Y[j] + x2 * y1 - y2 * x1);
          distp := num / denom;
          if GreaterThan(distp, PARAMETERS.DIST) then
            CMV[7] := true;
        end;
      end;
    end;
  end;

  { LIC 8 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
      if GreaterThan(Dist(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]), PARAMETERS.LENGTH1) then
        CMV[8] := true;
  end;

  { LIC 9 }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if not CanContainInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
        CMV[9] := true;
    end;
  end;

  { LIC 10 }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      j := i + PARAMETERS.C_PTS + 1;
      k := j + PARAMETERS.D_PTS + 1;
      angle := AngleAtVertex(X[i], Y[i], X[j], Y[j], X[k], Y[k], defined);
      if defined then
      begin
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
          CMV[10] := true;
      end;
    end;
  end;

  { LIC 11 }
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      if GreaterThan(TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]), PARAMETERS.AREA1) then
        CMV[11] := true;
    end;
  end;

  { LIC 12 }
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
      if LessThan(X[i + PARAMETERS.G_PTS + 1] - X[i], 0.0) then
        CMV[12] := true;
  end;

  { LIC 13 }
  if NUMPOINTS >= 3 then
  begin
    found1 := false;
    found2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      distp := Dist(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if GreaterThan(distp, PARAMETERS.LENGTH1) then
        found1 := true;
      if LessThan(distp, PARAMETERS.LENGTH2) then
        found2 := true;
    end;
    CMV[13] := found1 and found2;
  end;

  { LIC 14 }
  if NUMPOINTS >= 5 then
  begin
    found1 := false;
    found2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      j := i + PARAMETERS.A_PTS + 1;
      k := j + PARAMETERS.B_PTS + 1;
      if not CanContainInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS1) then
        found1 := true;
      if CanContainInCircle(X[i], Y[i], X[j], Y[j], X[k], Y[k], PARAMETERS.RADIUS2) then
        found2 := true;
    end;
    CMV[14] := found1 and found2;
  end;

  { LIC 15 }
  if NUMPOINTS >= 5 then
  begin
    found1 := false;
    found2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      j := i + PARAMETERS.E_PTS + 1;
      k := j + PARAMETERS.F_PTS + 1;
      distp := TriangleArea(X[i], Y[i], X[j], Y[j], X[k], Y[k]);
      if GreaterThan(distp, PARAMETERS.AREA1) then
        found1 := true;
      if LessThan(distp, PARAMETERS.AREA2) then
        found2 := true;
    end;
    CMV[15] := found1 and found2;
  end;

  { PUM off-diagonal elements }
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i <> j then
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
          ORR: PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
    end;
  end;

  { FUV }
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      alltrue := true;
      for j := 1 to 15 do
        if not PUM[i, j] then
          alltrue := false;
      FUV[i] := alltrue;
    end;
  end;

  { LAUNCH }
  LAUNCH := true;
  for i := 1 to 15 do
    if not FUV[i] then
      LAUNCH := false;
end;

end.
